import { Router } from 'express';
import { AppointmentController } from '../controllers/AppointmentController';
import { ScheduleAppointmentUseCase } from '../../application/use-cases/ScheduleAppointment.use-case';
import { CancelAppointmentUseCase } from '../../application/use-cases/CancelAppointment.use-case';
import { ConfirmAppointmentUseCase } from '../../application/use-cases/ConfirmAppointment.use-case';
import { CompleteAppointmentUseCase } from '../../application/use-cases/CompleteAppointment.use-case';
import { GetAppointmentUseCase } from '../../application/use-cases/GetAppointment.use-case';
import { ListAppointmentsUseCase } from '../../application/use-cases/ListAppointments.use-case';
import { SupabaseAppointmentRepository } from '../../infrastructure/persistence/SupabaseAppointmentRepository';

/**
 * Create appointment routes
 */
export function createAppointmentRoutes(): Router {
  const router = Router();

  // Initialize repository
  const supabaseUrl = process.env.SUPABASE_URL!;
  const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;
  const repository = new SupabaseAppointmentRepository(supabaseUrl, supabaseKey);

  // Initialize use cases
  const scheduleAppointmentUseCase = new ScheduleAppointmentUseCase(repository);
  const cancelAppointmentUseCase = new CancelAppointmentUseCase(repository);
  const confirmAppointmentUseCase = new ConfirmAppointmentUseCase(repository);
  const completeAppointmentUseCase = new CompleteAppointmentUseCase(repository);
  const getAppointmentUseCase = new GetAppointmentUseCase(repository);
  const listAppointmentsUseCase = new ListAppointmentsUseCase(repository);

  // Initialize controller
  const controller = new AppointmentController(
    scheduleAppointmentUseCase,
    cancelAppointmentUseCase,
    confirmAppointmentUseCase,
    completeAppointmentUseCase,
    getAppointmentUseCase,
    listAppointmentsUseCase
  );

  // Routes
  router.post('/appointments', (req, res) => controller.scheduleAppointment(req, res));
  router.get('/appointments/:id', (req, res) => controller.getAppointment(req, res));
  router.get('/appointments', (req, res) => controller.listAppointments(req, res));
  router.post('/appointments/:id/confirm', (req, res) => controller.confirmAppointment(req, res));
  router.post('/appointments/:id/complete', (req, res) => controller.completeAppointment(req, res));
  router.post('/appointments/:id/cancel', (req, res) => controller.cancelAppointment(req, res));

  return router;
}

